import heapq
from collections import defaultdict
import math

def agent_step(state, history):
    def heuristic(a, b):
        return abs(a[0] - b[0]) + abs(a[1] - b[1])  # Manhattan distance

    def a_star_search(start, goal, walls, blocks, historical_failures, direction_success_rates):
        frontier = []
        heapq.heappush(frontier, (0, start))
        came_from = {}
        cost_so_far = {}
        came_from[start] = None
        cost_so_far[start] = 0

        while frontier:
            current_cost, current = heapq.heappop(frontier)

            if current == goal:
                break

            for dx, dy in [(-3, 0), (3, 0), (0, -3), (0, 3)]:  # Left, Right, Up, Down
                next_step = (current[0] + dx, current[1] + dy)
                if next_step in walls or next_step in blocks:
                    continue
                # Adjust cost based on historical failures for the position
                failure_penalty = historical_failures.get(next_step, 0) * 0.5  # Penalize positions with past failures
                direction_key = None
                if dx == 3: direction_key = "MOVE_RIGHT"
                elif dx == -3: direction_key = "MOVE_LEFT"
                elif dy == -3: direction_key = "MOVE_UP"
                elif dy == 3: direction_key = "MOVE_DOWN"
                if direction_key and direction_key in direction_success_rates:
                    success_bonus = direction_success_rates[direction_key] * 0.2  # Reward directions with high success
                else:
                    success_bonus = 0
                new_cost = cost_so_far[current] + 1 + failure_penalty - success_bonus
                if next_step not in cost_so_far or new_cost < cost_so_far[next_step]:
                    cost_so_far[next_step] = new_cost
                    priority = new_cost + heuristic(goal, next_step)
                    heapq.heappush(frontier, (priority, next_step))
                    came_from[next_step] = current

        if goal not in came_from:
            return None  # No path found
        current = goal
        path = []
        while current != start:
            path.append(current)
            current = came_from[current]
        path.reverse()
        return path  # List of positions in path

    def get_move_direction(from_pos, to_pos):
        if from_pos[0] < to_pos[0]:
            return "MOVE_RIGHT"
        elif from_pos[0] > to_pos[0]:
            return "MOVE_LEFT"
        elif from_pos[1] < to_pos[1]:
            return "MOVE_DOWN"
        elif from_pos[1] > to_pos[1]:
            return "MOVE_UP"
        return None

    def analyze_history(history):
        direction_success = defaultdict(int)  # Successes per direction
        direction_failures = defaultdict(int)  # Failures per direction
        historical_failures = defaultdict(int)  # Failures per position
        for turn in history:
            action = turn["action"].get("action")
            if action in ["MOVE_RIGHT", "MOVE_LEFT", "MOVE_UP", "MOVE_DOWN"]:
                if turn["moved"]:
                    direction_success[action] += 1
                else:
                    direction_failures[action] += 1
                    # Record failure for the attempted position
                    prev_pos = tuple(turn["state"]["player"]["position"])  # Position before move
                    if action == "MOVE_RIGHT":
                        historical_failures[(prev_pos[0] + 3, prev_pos[1])] += 1
                    elif action == "MOVE_LEFT":
                        historical_failures[(prev_pos[0] - 3, prev_pos[1])] += 1
                    elif action == "MOVE_UP":
                        historical_failures[(prev_pos[0], prev_pos[1] - 3)] += 1
                    elif action == "MOVE_DOWN":
                        historical_failures[(prev_pos[0], prev_pos[1] + 3)] += 1
        direction_success_rates = {}
        for direction in direction_success:
            total_attempts = direction_success[direction] + direction_failures[direction]
            if total_attempts > 0:
                direction_success_rates[direction] = direction_success[direction] / total_attempts
        return direction_success_rates, dict(historical_failures)

    def is_stuck(history):
        return len(history) >= 3 and not any(turn["moved"] for turn in history[-3:])

    player_pos = tuple(state["player"]["position"])
    goals = state["objects"]["goals"]
    walls = {tuple(wall["position"]) for wall in state["objects"]["walls"]}
    blocks = {tuple(block["position"]) for block in state["objects"]["blocks"]}

    # Update blocks with heuristic hints
    if state["movement"]["right_blocked"]:
        blocks.add((player_pos[0] + 3, player_pos[1]))
    if state["movement"]["left_blocked"]:
        blocks.add((player_pos[0] - 3, player_pos[1]))
    if state["movement"]["up_blocked"]:
        blocks.add((player_pos[0], player_pos[1] - 3))
    if state["movement"]["down_blocked"]:
        blocks.add((player_pos[0], player_pos[1] + 3))

    direction_success_rates, historical_failures = analyze_history(history)

    if goals and state["resources"]["steps_remaining"] > 0:
        goal_pos = tuple(goals[0]["position"])  # Target the first goal
        path = a_star_search(player_pos, goal_pos, walls, blocks, historical_failures, direction_success_rates)

        if path:
            next_step = path[0]
            move_direction = get_move_direction(player_pos, next_step)
            return {"action": move_direction}

        # Proactive probing: Choose direction with highest success rate
        directions = ["MOVE_RIGHT", "MOVE_LEFT", "MOVE_UP", "MOVE_DOWN"]
        if direction_success_rates:
            best_direction = max(directions, key=lambda d: direction_success_rates.get(d, 0))
            return {"action": best_direction}

    if is_stuck(history) or state["resources"]["steps_remaining"] < 10:
        selectables = state["objects"]["selectables"]
        if selectables and goals:
            def selectable_score(selectable):
                sel_pos = tuple(selectable["position"])
                nearest_distance = min(heuristic(sel_pos, tuple(g["position"])) for g in goals)
                sel_success = sum(direction_success_rates.get(d, 0) for d in ["MOVE_RIGHT", "MOVE_LEFT", "MOVE_UP", "MOVE_DOWN"])  # Average success rate
                return nearest_distance - (sel_success * 5)  # Lower score is better
            best_selectable = min(selectables, key=selectable_score)
            if tuple(best_selectable["position"]) != player_pos:
                return {"action": "CLICK", "target_position": best_selectable["position"]}

    # Fallback to cycle, sorted by success rates
    cycle = ["MOVE_RIGHT", "MOVE_DOWN", "MOVE_LEFT", "MOVE_UP"]
    sorted_cycle = sorted(cycle, key=lambda d: direction_success_rates.get(d, 0), reverse=True)
    step = len(history)
    return {"action": sorted_cycle[step % len(sorted_cycle)]}
